import { writeFile } from "node:fs/promises";
import path from "node:path";

import type { Command } from "commander";

import { computeRunKey } from "../cache/run-key";
import {
  applyModelOverrides,
  findUnsupportedBaselineKeys,
  filterToAppliedBenchmarkConfig
} from "../config/resolution";
import { fileExists, readJson, readYaml } from "../config/loader";
import { LocalStateSchema, RunRecordSchema, SweepConfigSchema, type LocalState, type RunRecord } from "../config/schema";
import { buildComparisonCsv, buildModelSummaryCsv, type ComparisonRow } from "../reporter/csv";
import { appendRunRecord, findLatestRunRecordByRunKey, loadRunRecords, summarizeRecords } from "../reporter/results";
import { printModelComparison, type LoggerLike } from "../reporter/terminal";
import { createBenchInput, type BenchRunner } from "../runner/llama-bench";
import { inferLlamaBenchBinaryFingerprint } from "../runner/bench-binary-fingerprint";
import type { BenchCapabilities } from "../runner/llama-bench-capabilities";
import { probeLlamaBenchCapabilities } from "../runner/llama-bench-capabilities";

interface CompareOptions {
  model: string[];
  config?: string;
  rerun?: boolean;
  retryFailed?: boolean;
}

interface CompareCommandDeps {
  benchRunner: BenchRunner;
  benchCapabilities?: BenchCapabilities;
  cwd?: () => string;
  logger?: LoggerLike;
  now?: () => Date;
}

function collectString(value: string, previous: string[]): string[] {
  return [...previous, value];
}

function sanitizeFilePart(value: string): string {
  return value.replace(/[^a-zA-Z0-9._-]/g, "-");
}

function tuningSnapshotToRecord(source: Record<string, unknown>): Record<string, string | number | boolean> {
  const out: Record<string, string | number | boolean> = {};
  for (const [key, value] of Object.entries(source)) {
    if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
      out[key] = value;
    }
  }
  return out;
}

function resolveModelPath(state: LocalState, modelRef: string, configModels: Array<{ path: string; name: string }>): {
  modelName: string;
  modelPath: string;
} {
  if (modelRef.includes("/") || modelRef.endsWith(".gguf")) {
    return { modelName: path.basename(modelRef, path.extname(modelRef)), modelPath: modelRef };
  }

  const fromConfig = configModels.find((item) => item.name === modelRef);
  if (fromConfig) {
    return { modelName: fromConfig.name, modelPath: fromConfig.path };
  }

  const fromState = state.models.find((item) => item.name === modelRef);
  if (fromState) {
    return { modelName: fromState.name, modelPath: fromState.path };
  }

  throw new Error(`Model '${modelRef}' could not be resolved`);
}

function buildCacheHitRecord(base: Omit<RunRecord, "metrics" | "status" | "error">, reused: RunRecord): RunRecord {
  return RunRecordSchema.parse({
    ...base,
    metrics: reused.metrics,
    status: "success",
    error: null,
    cache: {
      hit: true,
      reused_run_id: reused.id
    }
  });
}

export function registerCompareCommand(command: Command, deps: CompareCommandDeps): void {
  const cwd = deps.cwd ?? (() => process.cwd());
  const logger = deps.logger ?? console;
  const now = deps.now ?? (() => new Date());

  command
    .command("compare")
    .description("Benchmark models head-to-head on baseline configuration")
    .requiredOption("-m, --model <model>", "Model name or path (repeat for multiple models)", collectString, [])
    .option("-c, --config <path>", "Config path", "sweep-config.yaml")
    .option("--rerun", "Ignore successful benchmark cache hits and execute all planned runs")
    .option("--retry-failed", "Skip successful cache hits, but rerun failures (based on latest record per run key)")
    .action(async (options: CompareOptions) => {
      if (options.model.length < 2) {
        throw new Error("Provide at least two --model values for comparison");
      }

      const root = cwd();
      const statePath = path.join(root, ".lmstudio-bench.json");
      if (!(await fileExists(statePath))) {
        throw new Error("Run `lmstudio-bench setup` first");
      }

      const configPath = path.join(root, options.config ?? "sweep-config.yaml");
      const state = await readJson(statePath, LocalStateSchema);
      const capabilities =
        deps.benchCapabilities ?? (await probeLlamaBenchCapabilities(state.llama_bench_path));
      for (const warning of capabilities.warnings) {
        logger.log(`llama-bench capabilities: ${warning}`);
      }

      const config = await readYaml(configPath, SweepConfigSchema);
      const runnerIdentity =
        (await deps.benchRunner.getRunnerIdentity?.({ llamaBenchPath: state.llama_bench_path })) ??
        (await inferLlamaBenchBinaryFingerprint(state.llama_bench_path));

      const rows: ComparisonRow[] = [];
      let hadFailures = false;

      for (const modelRef of options.model) {
        const model = resolveModelPath(state, modelRef, config.models);
        const resolvedConfig = applyModelOverrides(config, {
          name: model.modelName,
          path: model.modelPath
        });
        const unsupportedBaselineKeys = findUnsupportedBaselineKeys(resolvedConfig.baseline, capabilities);
        if (unsupportedBaselineKeys.length > 0) {
          logger.log(
            `Ignoring unsupported baseline fields for ${model.modelName}: ${unsupportedBaselineKeys.join(", ")}`
          );
        }
        const promptTokens = resolvedConfig.workload.prompt_tokens[0];
        const generationTokens = resolvedConfig.workload.generation_tokens[0];
        if (typeof promptTokens !== "number" || typeof generationTokens !== "number") {
          throw new Error("Workload prompt/generation tokens are required");
        }
        const appliedBaseline = filterToAppliedBenchmarkConfig(resolvedConfig.baseline, capabilities);
        const requestedBaselineRecord = tuningSnapshotToRecord(
          resolvedConfig.baseline as unknown as Record<string, unknown>
        );
        const appliedBaselineRecord = tuningSnapshotToRecord(appliedBaseline as unknown as Record<string, unknown>);
        const modelRunsPath = path.join(root, "results", sanitizeFilePart(model.modelName), "runs.jsonl");
        const historicalRecords = await loadRunRecords(modelRunsPath);
        const modelRecords: RunRecord[] = [];

        for (let repetition = 1; repetition <= resolvedConfig.workload.repetitions; repetition += 1) {
          const runKey = computeRunKey({
            benchCommand: "compare",
            modelPath: model.modelPath,
            appliedConfig: appliedBaseline,
            workload: { pp: promptTokens, tg: generationTokens },
            repetition: { runIndex: repetition, repetitions: resolvedConfig.workload.repetitions },
            hardware: state.hardware,
            runnerIdentity
          });

          const base = {
            id: `run-${now().toISOString().replace(/[:.]/g, "-")}-${repetition}`,
            timestamp: now().toISOString(),
            model: model.modelName,
            run_key: runKey,
            bench_command: "compare" as const,
            runner_identity: runnerIdentity,
            hardware: state.hardware,
            requested_config: requestedBaselineRecord,
            applied_config: appliedBaselineRecord,
            config: appliedBaselineRecord,
            capability_meta: {
              supported_keys: [...capabilities.supportedKeys].sort(),
              used_fallback: capabilities.usedFallback,
              warnings: capabilities.warnings.length > 0 ? [...capabilities.warnings] : undefined
            },
            workload: { pp: promptTokens, tg: generationTokens },
            run_index: repetition,
            repetitions: resolvedConfig.workload.repetitions
          };

          const latest = findLatestRunRecordByRunKey([...historicalRecords, ...modelRecords], runKey);
          const rerun = Boolean(options.rerun);
          const retryFailed = Boolean(options.retryFailed);
          const canReuseLatestSuccess = !rerun && latest?.status === "success";
          if (canReuseLatestSuccess) {
            const record = buildCacheHitRecord(base, latest);
            modelRecords.push(record);
            logger.log(
              `Cache hit: skipping benchmark${retryFailed ? " (--retry-failed)" : ""} (model=${
                model.modelName
              }, run_key=${runKey}, reused_run_id=${latest.id})`
            );
            continue;
          }

          try {
            const metrics = await deps.benchRunner.run(
              createBenchInput(
                state,
                model.modelPath,
                appliedBaseline,
                promptTokens,
                generationTokens,
                capabilities
              )
            );
            const record = RunRecordSchema.parse({
              ...base,
              metrics: {
                pp_tokens_per_sec: metrics.ppTokensPerSec,
                tg_tokens_per_sec: metrics.tgTokensPerSec,
                ttft_ms: metrics.ttftMs,
                wall_time_sec: metrics.wallTimeSec ?? null,
                peak_memory_mb: null,
                load_time_ms: null
              },
              status: "success",
              error: null
            });
            modelRecords.push(record);
            await appendRunRecord(modelRunsPath, record);
          } catch (error) {
            hadFailures = true;
            const record = RunRecordSchema.parse({
              ...base,
              metrics: {
                pp_tokens_per_sec: null,
                tg_tokens_per_sec: null,
                ttft_ms: null,
                wall_time_sec: null,
                peak_memory_mb: null,
                load_time_ms: null
              },
              status: "failed",
              error: {
                message: error instanceof Error ? error.message : String(error)
              }
            });
            modelRecords.push(record);
            await appendRunRecord(modelRunsPath, record);
          }
        }

        const summaries = summarizeRecords(modelRecords);
        if (summaries.length === 0) {
          continue;
        }
        const summaryCsv = buildModelSummaryCsv(summaries);
        await writeFile(path.join(root, "results", sanitizeFilePart(model.modelName), "summary.csv"), summaryCsv, "utf8");

        const best = summaries[0];
        if (!best) {
          continue;
        }
        rows.push({
          model: model.modelName,
          bestMedianTg: best.medianTg,
          bestMedianPp: best.medianPp,
          bestMedianTtft: best.medianTtft,
          bestConfigKey: best.configKey
        });
      }

      await writeFile(path.join(root, "results", "comparison.csv"), buildComparisonCsv(rows), "utf8");
      printModelComparison(logger, rows);
      if (hadFailures) {
        process.exitCode = 1;
      }
    });
}
