import { access, readFile, writeFile } from "node:fs/promises";
import { constants } from "node:fs";

import { parse, stringify } from "yaml";
import { type ZodSchema } from "zod";

export async function fileExists(filePath: string): Promise<boolean> {
  try {
    await access(filePath, constants.F_OK);
    return true;
  } catch {
    return false;
  }
}

export async function writeJson<T>(filePath: string, value: T): Promise<void> {
  await writeFile(filePath, `${JSON.stringify(value, null, 2)}\n`, "utf8");
}

export async function readJson<T>(filePath: string, schema: ZodSchema<T>): Promise<T> {
  const raw = await readFile(filePath, "utf8");
  const parsed = JSON.parse(raw) as unknown;
  return schema.parse(parsed);
}

export async function writeYaml<T>(filePath: string, value: T): Promise<void> {
  await writeFile(filePath, stringify(value), "utf8");
}

export async function readYaml<T>(filePath: string, schema: ZodSchema<T>): Promise<T> {
  const raw = await readFile(filePath, "utf8");
  const parsed = parse(raw) as unknown;
  return schema.parse(parsed);
}

export async function writeYamlIfMissing<T>(filePath: string, value: T): Promise<boolean> {
  if (await fileExists(filePath)) {
    return false;
  }
  await writeYaml(filePath, value);
  return true;
}
