import type { LocalState, SweepConfig } from "../config/schema";
import type { BenchmarkConfig } from "../sweep/sensitivity";
import { inferLlamaBenchBinaryFingerprint } from "./bench-binary-fingerprint";
import {
  benchCapabilitiesFromKeys,
  DEFAULT_FALLBACK_KEYS,
  type BenchCapabilities
} from "./llama-bench-capabilities";
import { parseLlamaBenchOutput } from "./parser";
import { runSubprocess } from "./subprocess";

export interface BenchRunInput {
  modelPath: string;
  llamaBenchPath: string;
  config: BenchmarkConfig;
  /** When omitted, conservative defaults match historical CLI behavior. */
  capabilities?: BenchCapabilities;
  workload: {
    promptTokens: number;
    generationTokens: number;
  };
}

export interface BenchRunResult {
  ppTokensPerSec: number;
  tgTokensPerSec: number;
  ttftMs: number | null;
  wallTimeSec?: number;
}

export interface BenchRunner {
  run(input: BenchRunInput): Promise<BenchRunResult>;
  /**
   * Optional stable identity string for the underlying `llama-bench` binary.
   *
   * Used for benchmark caching keys; defaults to a content-derived fingerprint of the binary on disk.
   */
  getRunnerIdentity?(input: { llamaBenchPath: string }): Promise<string>;
}

interface BuildArgsInput {
  modelPath: string;
  config: BenchmarkConfig;
  capabilities?: BenchCapabilities;
  workload: {
    promptTokens: number;
    generationTokens: number;
  };
}

export function buildLlamaBenchArgs(input: BuildArgsInput): string[] {
  const caps = input.capabilities ?? benchCapabilitiesFromKeys(DEFAULT_FALLBACK_KEYS, [], false);
  const args: string[] = [
    "-m",
    input.modelPath,
    "-p",
    String(input.workload.promptTokens),
    "-n",
    String(input.workload.generationTokens)
  ];

  if (caps.supportedKeys.has("n_ctx") && typeof input.config.n_ctx === "number") {
    args.push("-c", String(input.config.n_ctx));
  }
  if (caps.supportedKeys.has("n_batch")) {
    args.push("-b", String(input.config.n_batch));
  }
  if (caps.supportedKeys.has("n_ubatch")) {
    args.push("-ub", String(input.config.n_ubatch));
  }
  if (caps.supportedKeys.has("n_gpu_layers")) {
    args.push("-ngl", String(input.config.n_gpu_layers));
  }
  if (caps.supportedKeys.has("threads")) {
    args.push("-t", String(input.config.threads));
  }
  if (caps.supportedKeys.has("threads_batch") && typeof input.config.threads_batch === "number") {
    args.push("-tb", String(input.config.threads_batch));
  }
  if (caps.supportedKeys.has("kv_type_key")) {
    args.push("-ctk", String(input.config.kv_type_key));
  }
  if (caps.supportedKeys.has("kv_type_value")) {
    args.push("-ctv", String(input.config.kv_type_value));
  }
  if (caps.supportedKeys.has("flash_attention")) {
    args.push("-fa", input.config.flash_attention ? "1" : "0");
  }
  if (caps.supportedKeys.has("mmap")) {
    args.push("-mmp", input.config.mmap ? "1" : "0");
  }
  if (caps.supportedKeys.has("mlock")) {
    args.push("--mlock", input.config.mlock ? "1" : "0");
  }

  args.push("-r", "1", "-o", "json");
  return args;
}

export class LlamaBenchRunner implements BenchRunner {
  private readonly identityCache = new Map<string, string>();

  async getRunnerIdentity(input: { llamaBenchPath: string }): Promise<string> {
    const cached = this.identityCache.get(input.llamaBenchPath);
    if (cached) {
      return cached;
    }

    const identity = await inferLlamaBenchBinaryFingerprint(input.llamaBenchPath);
    this.identityCache.set(input.llamaBenchPath, identity);
    return identity;
  }

  async run(input: BenchRunInput): Promise<BenchRunResult> {
    const args = buildLlamaBenchArgs(input);
    const result = await runSubprocess(input.llamaBenchPath, args);
    if (result.exitCode !== 0) {
      throw new Error(result.stderr || `llama-bench failed with exit code ${result.exitCode}`);
    }

    const parsed = parseLlamaBenchOutput(result.stdout);
    return {
      ...parsed,
      wallTimeSec: Number((result.elapsedMs / 1000).toFixed(3))
    };
  }
}

export function createBenchRunner(): BenchRunner {
  return new LlamaBenchRunner();
}

export function createBenchInput(
  state: LocalState,
  modelPath: string,
  config: BenchmarkConfig,
  promptTokens: number,
  generationTokens: number,
  capabilities?: BenchCapabilities
): BenchRunInput {
  return {
    modelPath,
    llamaBenchPath: state.llama_bench_path,
    config,
    ...(capabilities !== undefined ? { capabilities } : {}),
    workload: {
      promptTokens,
      generationTokens
    }
  };
}
