import type { BenchmarkTuneKey, BenchCapabilities } from "../runner/llama-bench-capabilities";
import { BENCHMARK_TUNE_KEYS, benchCapabilitiesFromKeys, DEFAULT_FALLBACK_KEYS } from "../runner/llama-bench-capabilities";
import type { BenchmarkConfig } from "../sweep/sensitivity";
import { BenchmarkBaselineSchema, BenchmarkScanSchema, WorkloadSchema, type SweepConfig } from "./schema";

/**
 * @deprecated Prefer {@link probeLlamaBenchCapabilities}. Kept for tests and as the conservative fallback set.
 */
export const SUPPORTED_SCAN_KEYS = [
  "n_batch",
  "n_ubatch",
  "n_gpu_layers",
  "threads",
  "kv_type_key",
  "kv_type_value",
  "flash_attention",
  "mmap"
] as const satisfies readonly BenchmarkTuneKey[];

export type LegacySupportedScanKey = (typeof SUPPORTED_SCAN_KEYS)[number];

/** Capabilities used by resolution helpers (re-export shape from runner). */
export type { BenchCapabilities };

export function staticCapabilitiesFromLegacyList(): BenchCapabilities {
  return benchCapabilitiesFromKeys(SUPPORTED_SCAN_KEYS, [], false);
}

export interface ResolvedSweepConfig {
  baseline: SweepConfig["baseline"];
  scan: SweepConfig["scan"];
  workload: SweepConfig["workload"];
}

export function applyModelOverrides(
  config: SweepConfig,
  model: {
    name: string;
    path: string;
  }
): ResolvedSweepConfig {
  const matchedOverrides = config.model_overrides.filter((override) => {
    const nameMatch = override.match.name ? override.match.name === model.name : true;
    const pathMatch = override.match.path ? override.match.path === model.path : true;
    return nameMatch && pathMatch;
  });

  let baseline = { ...config.baseline };
  let scan = { ...config.scan };
  let workload = { ...config.workload };

  for (const override of matchedOverrides) {
    baseline = BenchmarkBaselineSchema.parse({ ...baseline, ...(override.baseline ?? {}) });
    scan = BenchmarkScanSchema.parse({ ...scan, ...(override.scan ?? {}) });
    workload = WorkloadSchema.parse({ ...workload, ...(override.workload ?? {}) });
  }

  return {
    baseline,
    scan,
    workload
  };
}

function isRecordKey(key: string): key is keyof SweepConfig["baseline"] {
  return key in BenchmarkBaselineSchema.shape;
}

/**
 * Pick only tuning fields that exist in `source` and are supported by the runner.
 */
export function filterToAppliedBenchmarkConfig(
  source: SweepConfig["baseline"] | BenchmarkConfig | Record<string, unknown>,
  capabilities: BenchCapabilities
): BenchmarkConfig {
  const out: Record<string, unknown> = {};
  for (const key of BENCHMARK_TUNE_KEYS) {
    if (!capabilities.supportedKeys.has(key)) {
      continue;
    }
    if (typeof source === "object" && source !== null && key in source) {
      out[key] = (source as Record<string, unknown>)[key];
    }
  }
  return out as BenchmarkConfig;
}

/** @deprecated Use {@link filterToAppliedBenchmarkConfig} */
export function filterBaselineForCapabilities(
  baseline: SweepConfig["baseline"],
  capabilities: BenchCapabilities
): BenchmarkConfig {
  return filterToAppliedBenchmarkConfig(baseline, capabilities);
}

export function filterScanForCapabilities(
  scan: SweepConfig["scan"],
  capabilities: BenchCapabilities
): Partial<SweepConfig["scan"]> {
  return Object.fromEntries(
    Object.entries(scan).filter(([key]) => {
      if (!isRecordKey(key)) {
        return false;
      }
      return capabilities.supportedKeys.has(key as BenchmarkTuneKey);
    })
  ) as Partial<SweepConfig["scan"]>;
}

export function findUnsupportedScanKeys(scan: SweepConfig["scan"], capabilities: BenchCapabilities): string[] {
  return Object.keys(scan).filter((key) => {
    if (!isRecordKey(key)) {
      return false;
    }
    const values = (scan as Record<string, unknown[]>)[key] ?? [];
    return (
      Array.isArray(values) &&
      values.length > 0 &&
      !capabilities.supportedKeys.has(key as BenchmarkTuneKey)
    );
  });
}

export function findUnsupportedBaselineKeys(
  baseline: SweepConfig["baseline"],
  capabilities: BenchCapabilities
): string[] {
  return Object.keys(baseline).filter(
    (key) => isRecordKey(key) && !capabilities.supportedKeys.has(key as BenchmarkTuneKey)
  );
}

export { BENCHMARK_TUNE_KEYS, benchCapabilitiesFromKeys, DEFAULT_FALLBACK_KEYS };
