import type { SweepConfig } from "../config/schema";

/**
 * Effective benchmark parameters for a single `llama-bench` invocation.
 * Only fields supported by the installed binary (see {@link BenchCapabilities}) should be present.
 */
export interface BenchmarkConfig {
  [key: string]: string | number | boolean | undefined;
  n_ctx?: number;
  n_batch: number;
  n_ubatch: number;
  n_gpu_layers: number;
  threads: number;
  threads_batch?: number;
  kv_type_key: string;
  kv_type_value: string;
  flash_attention: boolean;
  mmap: boolean;
  mlock?: boolean;
}

/** Baseline row from YAML (may include fields not passed to `llama-bench`). */
export type SensitivityBaseline = SweepConfig["baseline"] | BenchmarkConfig;

export interface SensitivityEntry {
  variedParam: keyof SweepConfig["scan"] | "baseline";
  config: BenchmarkConfig;
}

export function expandSensitivityScan(
  baseline: SensitivityBaseline,
  scan: Partial<SweepConfig["scan"]>
): SensitivityEntry[] {
  const deduped = new Map<string, SensitivityEntry>();
  const baselineEntry: SensitivityEntry = { variedParam: "baseline", config: baseline as BenchmarkConfig };
  deduped.set(JSON.stringify(baselineEntry.config), baselineEntry);

  const keys = Object.keys(scan) as Array<keyof SweepConfig["scan"]>;
  for (const key of keys) {
    const values = scan[key] ?? [];
    for (const value of values) {
      const nextConfig = { ...baseline, [key]: value } as BenchmarkConfig;
      const dedupeKey = JSON.stringify(nextConfig);
      if (!deduped.has(dedupeKey)) {
        deduped.set(dedupeKey, { variedParam: key, config: nextConfig });
      }
    }
  }

  return Array.from(deduped.values());
}
