import { createHash } from "node:crypto";

import type { LocalState } from "../config/schema";
import type { BenchmarkConfig } from "../sweep/sensitivity";

export type BenchCommandKind = "scan" | "compare";

export interface ComputeRunKeyInput {
  benchCommand: BenchCommandKind;
  modelPath: string;
  appliedConfig: BenchmarkConfig;
  workload: { pp: number; tg: number };
  repetition: { runIndex: number; repetitions: number };
  hardware: LocalState["hardware"];
  runnerIdentity: string;
}

function stableStringify(value: unknown): string {
  if (value === null || typeof value !== "object") {
    return JSON.stringify(value);
  }

  if (Array.isArray(value)) {
    return `[${value.map((item) => stableStringify(item)).join(",")}]`;
  }

  const entries = Object.entries(value as Record<string, unknown>)
    .filter(([, v]) => typeof v !== "undefined")
    .sort(([a], [b]) => (a < b ? -1 : a > b ? 1 : 0));

  return `{${entries.map(([k, v]) => `${JSON.stringify(k)}:${stableStringify(v)}`).join(",")}}`;
}

export function computeRunKey(input: ComputeRunKeyInput): string {
  const payload = stableStringify({
    v: 1,
    benchCommand: input.benchCommand,
    modelPath: input.modelPath,
    appliedConfig: input.appliedConfig,
    workload: input.workload,
    repetition: input.repetition,
    hardware: input.hardware,
    runnerIdentity: input.runnerIdentity
  });

  return createHash("sha256").update(payload, "utf8").digest("hex");
}
