import { runSubprocess } from "./subprocess";

/**
 * Logical tuning fields that may map to `llama-bench` CLI flags.
 * Detected at runtime from `llama-bench --help` where possible.
 */
export const BENCHMARK_TUNE_KEYS = [
  "n_ctx",
  "n_batch",
  "n_ubatch",
  "n_gpu_layers",
  "threads",
  "threads_batch",
  "kv_type_key",
  "kv_type_value",
  "flash_attention",
  "mmap",
  "mlock"
] as const;

export type BenchmarkTuneKey = (typeof BENCHMARK_TUNE_KEYS)[number];

export interface BenchCapabilities {
  readonly supportedKeys: ReadonlySet<BenchmarkTuneKey>;
  readonly warnings: readonly string[];
  readonly usedFallback: boolean;
}

/** Same surface as historically hardcoded integration (minus YAML-only fields). */
export const DEFAULT_FALLBACK_KEYS: ReadonlySet<BenchmarkTuneKey> = new Set([
  "n_batch",
  "n_ubatch",
  "n_gpu_layers",
  "threads",
  "kv_type_key",
  "kv_type_value",
  "flash_attention",
  "mmap"
]);

export function benchCapabilitiesFromKeys(
  keys: Iterable<BenchmarkTuneKey>,
  warnings: string[] = [],
  usedFallback = false
): BenchCapabilities {
  return {
    supportedKeys: new Set(keys),
    warnings,
    usedFallback
  };
}

export function benchCapabilitiesWithWarning(
  base: BenchCapabilities,
  message: string
): BenchCapabilities {
  return benchCapabilitiesFromKeys(base.supportedKeys, [...base.warnings, message], base.usedFallback);
}

/**
 * Strip leading backend noise (Metal/BLAS logs) so flag detection is stable.
 */
export function extractLlamaBenchHelpSection(raw: string): string {
  const lines = raw.split(/\r?\n/);
  const usageIndex = lines.findIndex((line) => /^\s*usage:\s*/i.test(line));
  if (usageIndex >= 0) {
    return lines.slice(usageIndex).join("\n");
  }
  const testParamsIndex = lines.findIndex((line) => /^\s*test parameters:\s*$/i.test(line));
  if (testParamsIndex >= 0) {
    return lines.slice(testParamsIndex).join("\n");
  }
  return raw;
}

/**
 * Parse `llama-bench --help` (or combined stdout/stderr) into supported tuning keys.
 * Degrades to {@link DEFAULT_FALLBACK_KEYS} when no flags match (empty / unknown help).
 */
export function parseCapabilitiesFromHelpText(raw: string): BenchCapabilities {
  const help = extractLlamaBenchHelpSection(raw);
  const supported = new Set<BenchmarkTuneKey>();

  // Real llama.cpp bench help uses lines like: "  -b, --batch-size <n>"
  if (/(?:^|\n)\s*-b,\s*--batch-size\b/m.test(help) || /\n\s*-b,\s*--batch-size\b/.test(help)) {
    supported.add("n_batch");
  }
  if (/(?:^|\n)\s*-ub,\s*--ubatch-size\b/m.test(help) || /\n\s*-ub,\s*--ubatch-size\b/.test(help)) {
    supported.add("n_ubatch");
  }
  if (/(?:^|\n)\s*-ctk,\s*--cache-type-k\b/m.test(help)) {
    supported.add("kv_type_key");
  }
  if (/(?:^|\n)\s*-ctv,\s*--cache-type-v\b/m.test(help)) {
    supported.add("kv_type_value");
  }
  // Avoid matching `-ts` (tensor-split): require long form or "-t, --threads"
  if (/(?:^|\n)\s*-t,\s*--threads\b/m.test(help)) {
    supported.add("threads");
  }
  if (/(?:^|\n)\s*-ngl,\s*--n-gpu-layers\b/m.test(help)) {
    supported.add("n_gpu_layers");
  }
  if (/(?:^|\n)\s*-fa,\s*--flash-attn\b/m.test(help)) {
    supported.add("flash_attention");
  }
  if (/(?:^|\n)\s*-mmp,\s*--mmap\b/m.test(help)) {
    supported.add("mmap");
  }
  // Context size (flag shape varies by version)
  if (
    /(?:^|\n)\s*-c,\s*--ctx-size\b/m.test(help) ||
    /(?:^|\n)\s*--ctx-size\b/m.test(help) ||
    /(?:^|\n)\s*-c,\s*--context-size\b/m.test(help)
  ) {
    supported.add("n_ctx");
  }
  if (/(?:^|\n)\s*-tb,\s*--threads-batch\b/m.test(help) || /(?:^|\n)\s*--threads-batch\b/m.test(help)) {
    supported.add("threads_batch");
  }
  if (/(?:^|\n)\s*-ml,\s*--mlock\b/m.test(help) || /(?:^|\n)\s*--mlock\b/m.test(help)) {
    supported.add("mlock");
  }

  if (supported.size === 0) {
    return benchCapabilitiesFromKeys(
      DEFAULT_FALLBACK_KEYS,
      ["Could not infer any benchmark flags from llama-bench help; using conservative defaults."],
      true
    );
  }

  return benchCapabilitiesFromKeys(supported, [], false);
}

export async function probeLlamaBenchCapabilities(llamaBenchPath: string): Promise<BenchCapabilities> {
  try {
    const result = await runSubprocess(llamaBenchPath, ["--help"]);
    const combined = `${result.stdout}\n${result.stderr}`;
    const helpBody = extractLlamaBenchHelpSection(combined);
    if (!helpBody.trim()) {
      return benchCapabilitiesFromKeys(
        DEFAULT_FALLBACK_KEYS,
        [`llama-bench --help produced no usable text (exit ${result.exitCode}); using defaults.`],
        true
      );
    }
    const parsed = parseCapabilitiesFromHelpText(combined);
    if (result.exitCode !== 0 && parsed.warnings.length === 0) {
      return benchCapabilitiesWithWarning(
        parsed,
        `llama-bench --help exited with code ${result.exitCode}; capabilities may be incomplete.`
      );
    }
    return parsed;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return benchCapabilitiesFromKeys(
      DEFAULT_FALLBACK_KEYS,
      [`Failed to run llama-bench --help (${message}); using defaults.`],
      true
    );
  }
}
