import { Command } from "commander";

import type { DiscoveryService } from "../bootstrap/discovery";
import { createDiscoveryService } from "../bootstrap/discovery";
import { createBenchRunner, type BenchRunner } from "../runner/llama-bench";
import type { BenchCapabilities } from "../runner/llama-bench-capabilities";
import { registerCompareCommand } from "./compare";
import { registerListModelsCommand } from "./list-models";
import { registerReportCommand } from "./report";
import { registerScanCommand } from "./scan";
import { registerSetupCommand } from "./setup";

export const CLI_NAME = "lmstudio-bench";

export interface CliDependencies {
  discoveryService?: DiscoveryService;
  benchRunner?: BenchRunner;
  /** When set, `scan` / `compare` / `setup` skip probing `llama-bench --help` (faster tests). */
  benchCapabilities?: BenchCapabilities;
  logger?: Pick<Console, "log" | "error">;
}

export function createCli(deps: CliDependencies = {}): Command {
  const command = new Command().name(CLI_NAME).description("Benchmark llama.cpp configurations");
  const logger = deps.logger ?? console;
  const benchRunner = deps.benchRunner ?? createBenchRunner();
  registerSetupCommand(command, {
    discoveryService: deps.discoveryService ?? createDiscoveryService(),
    ...(deps.benchCapabilities !== undefined ? { benchCapabilities: deps.benchCapabilities } : {}),
    logger
  });
  registerListModelsCommand(command, {
    logger
  });
  registerScanCommand(command, {
    benchRunner,
    ...(deps.benchCapabilities !== undefined ? { benchCapabilities: deps.benchCapabilities } : {}),
    logger
  });
  registerCompareCommand(command, {
    benchRunner,
    ...(deps.benchCapabilities !== undefined ? { benchCapabilities: deps.benchCapabilities } : {}),
    logger
  });
  registerReportCommand(command, {
    logger
  });
  return command;
}
